using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    [Editor(typeof(SafeDropDownEditor), typeof(UITypeEditor))]
    public string SelectedOption { get; set; }
}

// .NET 9: IWindowsFormsEditorService.DropDownControl(null) now throws
// ArgumentNullException. Use CloseDropDown() to dismiss the dropdown instead.
public class SafeDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(ITypeDescriptorContext context,
        IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null) return value;

        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        listBox.Click += (s, e) =>
        {
            // .NET 9 breaking change: call CloseDropDown() instead of DropDownControl(null)
            editorService.CloseDropDown();
        };

        editorService.DropDownControl(listBox);
        return listBox.SelectedItem ?? value;
    }
}

