using System.Windows.Forms;

static class Program
{
    [STAThread]
    static void Main()
    {
        ApplicationConfiguration.Initialize();

        // .NET 9 breaking change: The default ToolStrip/StatusStrip renderer changed
        // from Professional to System. Restore the .NET 8 appearance explicitly.
        ToolStripManager.RenderMode = ToolStripManagerRenderMode.Professional;

        var form = new Form { Text = "WinForms App" };

        var statusStrip = new StatusStrip();
        statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        form.Controls.Add(statusStrip);
        form.Controls.Add(new MyControl { Dock = DockStyle.Fill });

        Application.Run(form);
    }
}

